arguments.prompt:
You are implementing a Blazor Web App for shipment tracking. The project has been scaffolded at `/tmp/sv-55f0cbfecfe84b14a7913584f1086afc/ShipmentTracker/` using `dotnet new blazor -int Auto -ai -au Individual`.

The project structure:
- **ShipmentTracker/** (server project): hosts the app, has EF Core with SQLite, ASP.NET Identity
- **ShipmentTracker.Client/** (WebAssembly project): all interactive components must go here

## CRITICAL Auto-mode rules:
- Interactive components MUST live in `.Client` project
- No direct DB access from `.Client` — use HTTP APIs
- Both Program.cs files must register matching service interfaces
- Don't add `@rendermode` to pages — global interactivity is already set in App.razor

## Tasks to complete (do them in order):

### 1. Create shared model in Client project

Create `ShipmentTracker.Client/Models/Shipment.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}
```

### 2. Create service interface in Client project

Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<Shipment> CreateShipmentAsync(Shipment shipment);
    Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status);
}
```

### 3. Create Client-side HTTP implementation

Create `ShipmentTracker.Client/Services/ShipmentHttpService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var response = await http.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", status);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }
}
```

### 4. Register HttpClient and service in Client Program.cs

Edit `ShipmentTracker.Client/Program.cs` to add:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddHttpClient("ServerAPI", client =>
    client.BaseAddress = new Uri(builder.HostEnvironment.BaseAddress));
builder.Services.AddScoped(sp =>
    sp.GetRequiredService<IHttpClientFactory>().CreateClient("ServerAPI"));
builder.Services.AddScoped<IShipmentService, ShipmentHttpService>();

await builder.Build().RunAsync();
```

### 5. Add Shipment entity to server DbContext

Edit `ShipmentTracker/Data/ApplicationDbContext.cs`:
```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Shipment> Shipments => Set<Shipment>();
}
```

### 6. Create server-side service implementation

Create `ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments.OrderByDescending(s => s.ShippedDate).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        shipment.TrackingNumber = $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(1000, 9999)}";
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return shipment;
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException("Shipment not found");
        shipment.Status = status;
        if (status == ShipmentStatus.Delivered)
            shipment.ActualDelivery = DateTime.UtcNow;
        await db.SaveChangesAsync();
        return shipment;
    }
}
