    [Parameter]
    public string? TrackingNumber { get; set; }

    private string searchTrackingNumber = string.Empty;
    private Shipment? shipment;
    private bool isSearching;
    private bool searched;
    private string lastSearched = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrEmpty(TrackingNumber))
        {
            searchTrackingNumber = TrackingNumber;
            await SearchShipment();
        }
    }

    private async Task HandleKeyPress(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(searchTrackingNumber)) return;

        isSearching = true;
        searched = false;
        lastSearched = searchTrackingNumber.Trim();

        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(lastSearched);

        isSearching = false;
        searched = true;
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 55,
        _ => 0
    };
}
