@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>🚚 Dispatcher Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-success" @onclick="ShowCreateForm">
            ➕ New Shipment
        </button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-header">Create New Shipment</div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-4">
                    <label class="form-label">Origin</label>
                    <input type="text" class="form-control" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Destination</label>
                    <input type="text" class="form-control" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Customer Email</label>
                    <input type="email" class="form-control" @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Description</label>
                    <input type="text" class="form-control" @bind="newShipment.Description" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-12">
                    <button class="btn btn-primary me-2" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p class="text-muted">No shipments match the current filters.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Shipped</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>
                            <span class="badge @GetStatusBadge(shipment.Status)">@shipment.Status</span>
                        </td>
                        <td>@shipment.ShippedDate.ToString("MMM dd, yyyy")</td>
                        <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm d-inline-block w-auto"
                                    @onchange="e => UpdateStatus(shipment.Id, e)">
                                @foreach (var s in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@s" selected="@(s == shipment.Status)">@s</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;
    private bool showCreateForm;
    private Shipment newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };

    private IEnumerable<Shipment> FilteredShipments =>
        (shipments ?? [])
        .Where(s => string.IsNullOrEmpty(filterText)
            || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)
            || s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(statusFilter)
            || s.Status.ToString() == statusFilter);

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        showCreateForm = true;
        newShipment = new Shipment { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };
    }

    private async Task CreateShipment()
    {
        newShipment.ShippedDate = DateTime.UtcNow;
        newShipment.Status = ShipmentStatus.Pending;
        await ShipmentService.CreateShipmentAsync(newShipment);
        showCreateForm = false;
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(int id, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var status))
        {
            await ShipmentService.UpdateShipmentStatusAsync(id, status);
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

