else if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@lastSearched</strong>. Please check the number and try again.
    </div>
}
else if (shipment is not null)
{
    <div class="card shadow">
        <div class="card-header bg-dark text-white d-flex justify-content-between">
            <span>Tracking: <strong>@shipment.TrackingNumber</strong></span>
            <span class="badge @GetStatusBadge(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-6">
                    <h5>Shipment Details</h5>
                    <dl class="row">
                        <dt class="col-sm-5">Description</dt>
                        <dd class="col-sm-7">@shipment.Description</dd>
                        <dt class="col-sm-5">Origin</dt>
                        <dd class="col-sm-7">@shipment.Origin</dd>
                        <dt class="col-sm-5">Destination</dt>
                        <dd class="col-sm-7">@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <h5>Delivery Information</h5>
                    <dl class="row">
                        <dt class="col-sm-5">Shipped Date</dt>
                        <dd class="col-sm-7">@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>
                        <dt class="col-sm-5">Est. Delivery</dt>
                        <dd class="col-sm-7">
                            <strong>@shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</strong>
                        </dd>
                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt class="col-sm-5">Delivered On</dt>
                            <dd class="col-sm-7 text-success">
                                <strong>@shipment.ActualDelivery.Value.ToString("MMMM dd, yyyy")</strong>
                            </dd>
                        }
                    </dl>
                </div>
            </div>

            <hr />
            <h5>Shipment Progress</h5>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @GetProgressPercent(shipment.Status)%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public string? TrackingNumber { get; set; }

    private string searchTrackingNumber = string.Empty;
    private Shipment? shipment;
    private bool isSearching;
    private bool searched;
    private string lastSearched = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrEmpty(TrackingNumber))
        {
            searchTrackingNumber = TrackingNumber;
            await SearchShipment();
        }
    }

    private async Task HandleKeyPress(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(searchTrackingNumber)) return;

        isSearching = true;
        searched = false;
        lastSearched = searchTrackingNumber.Trim();

        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(lastSearched);

        isSearching = false;
        searched = true;
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 55,
        _ => 0
    };
}

