using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Pages;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Components;
using ShipmentTracker.Components.Account;
using ShipmentTracker.Data;
using ShipmentTracker.Services;

// Shipment API endpoints
var shipments = app.MapGroup("api/shipments");

shipments.MapGet("/", async (IShipmentService svc) =>
    Results.Ok(await svc.GetAllShipmentsAsync()))
    .RequireAuthorization();

shipments.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService svc) =>
{
    var shipment = await svc.GetShipmentByTrackingNumberAsync(trackingNumber);
    return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
}).RequireAuthorization();

shipments.MapPost("/", async (Shipment shipment, IShipmentService svc) =>
{
    var created = await svc.CreateShipmentAsync(shipment);
    return Results.Created($"api/shipments/track/{created.TrackingNumber}", created);
}).RequireAuthorization();

shipments.MapPut("/{id}/status", async (int id, ShipmentStatus status, IShipmentService svc) =>
{
    var updated = await svc.UpdateShipmentStatusAsync(id, status);
    return Results.Ok(updated);
}).RequireAuthorization();

// Seed sample data
using (var scope = app.Services.CreateScope())
{
    var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
    await SeedData.InitializeAsync(db);
}

app.Run();

